  let jni = Java.loadClass("org.lwjgl.system.jni.JNINativeInterface");
  jni.nGetJavaVM(smallBuf);
  nat.callPPP(jni.NewGlobalRef(v), smallBuf, plat.get() == plat.WINDOWS ? base + data.w : base);
